// runOnceForAllItems: process all merged beach+API items, expand into one item per photo.
// runOnceForEachItem cannot return arrays in Code v2 — use this mode instead.
const out = [];

for (const inp of $input.all()) {
  const item = inp.json;
  const praia_id = item.praia_id;

  if (item.error) {
    console.log(`Praia ${praia_id}: API error — ${item.error.message ?? JSON.stringify(item.error)}`);
    continue;
  }

  const photos = item.photos ?? [];

  if (photos.length === 0) {
    console.log(`Praia ${praia_id}: no photos returned`);
    continue;
  }

  photos.slice(0, 10).forEach((photo, idx) => {
    out.push({
      json: {
        praia_id: Number(praia_id),
        ordem: idx,
        photoName: String(photo.name),
        widthPx: photo.widthPx ?? null,
        heightPx: photo.heightPx ?? null,
        attribution: photo.authorAttributions?.[0]?.displayName ?? null,
      }
    });
  });

  console.log(`Praia ${praia_id}: ${Math.min(photos.length, 10)} photos`);
}

console.log(`Total photo items to resolve: ${out.length}`);
return out;

// Pair each resolved photoUri with the corresponding photo metadata (by position).
const out = [];

for (const inp of $input.all()) {
  const item = inp.json;
  const photoUri = item.photoUri ?? null;

  if (!photoUri) {
    console.log(`Praia ${item.praia_id} ordem ${item.ordem}: photoUri missing, skipping`);
    continue;
  }

  out.push({
    json: {
      praia_id: item.praia_id,
      ordem: item.ordem,
      url: String(photoUri),
      largura: item.widthPx,
      altura: item.heightPx,
      attribution: item.attribution,
    }
  });
}

return out;

// Build bulk SQL: replace photos for beaches that returned any, AND mark
// every processed beach as verified (so beaches with zero photos don't get
// re-fetched on the next run).
const rows = $input.all().map(i => i.json);
const allCandidates = $('Buscar Praias Sem Fotos').all().map(i => i.json);
const processedIds = [...new Set(allCandidates.map(c => Number(c.praia_id)))];

if (processedIds.length === 0) {
  console.log('No beaches to verify');
  return [];
}

const esc = (v) => v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
const num = (v) => v == null ? 'NULL' : String(Number(v));

let sql = '';

if (rows.length > 0) {
  const praiaIdsWithFotos = [...new Set(rows.map(r => Number(r.praia_id)))];
  const values = rows.map(r =>
    `(${num(r.praia_id)}, ${esc(r.url)}, ${num(r.largura)}, ${num(r.altura)}, ${esc(r.attribution)}, ${num(r.ordem)}, 'google_places')`
  ).join(',\n');
  sql += `DELETE FROM praia_fotos WHERE praia_id IN (${praiaIdsWithFotos.join(',')});\n`;
  sql += `INSERT INTO praia_fotos (praia_id, url, largura, altura, attribution, ordem, fonte) VALUES ${values};\n`;
}

// Always mark processed beaches as verified, even if zero photos were found.
sql += `UPDATE praias SET fotos_verificadas_em = NOW() WHERE id IN (${processedIds.join(',')});\n`;

console.log(`Will write ${rows.length} photos and mark ${processedIds.length} beaches as verified`);
return [{ json: { sql, total: rows.length, praias: processedIds.length } }];
